func (siw *ServerInterfaceWrapper) HandleAppleWebhook(c *gin.Context) {

	for _, middleware := range siw.HandlerMiddlewares {
		middleware(c)
		if c.IsAborted() {
			return
		}
	}

	siw.Handler.HandleAppleWebhook(c)
}

